import { Component } from '@angular/core';

@Component({
  selector: 'app-criar-personagem',
  templateUrl: './criar-personagem.component.html',
  styleUrls: ['./criar-personagem.component.css']
})
export class CriarPersonagemComponent {
  etapa = 1; // Controla em qual passo do formulário o usuário está
  personagem = {
    raca: '',
    classe: '',
    atributos: {
      forca: 0,
      destreza: 0,
      constituicao: 0,
      inteligencia: 0,
      sabedoria: 0,
      carisma: 0
    }
  };

  racas = [
    { nome: 'Humano', img: 'assets/racas/humano.png' },
    { nome: 'Elfo', img: 'assets/racas/elfo.png' },
    { nome: 'Anão', img: 'assets/racas/anao.png' },
    { nome: 'Orc', img: 'assets/racas/orc.png' },
    { nome: 'Gnomo', img: 'assets/racas/gnomo.png' },
    { nome: 'Tiefling', img: 'assets/racas/tiefling.png' },
    { nome: 'Draconato', img: 'assets/racas/draconato.png' },
    { nome: 'Meio-Elfo', img: 'assets/racas/meio-elfo.png' },
    { nome: 'Meio-Orc', img: 'assets/racas/meio-orc.png' },
    { nome: 'Halfling', img: 'assets/racas/halfling.png' }
  ];

  classes = [
    { nome: 'Guerreiro', img: 'assets/classes/guerreiro.png' },
    { nome: 'Mago', img: 'assets/classes/mago.png' },
    { nome: 'Ladino', img: 'assets/classes/ladino.png' },
    { nome: 'Clérigo', img: 'assets/classes/clerigo.png' },
    { nome: 'Paladino', img: 'assets/classes/paladino.png' },
    { nome: 'Bardo', img: 'assets/classes/bardo.png' },
    { nome: 'Druida', img: 'assets/classes/druida.png' },
    { nome: 'Feiticeiro', img: 'assets/classes/feiticeiro.png' },
    { nome: 'Bruxo', img: 'assets/classes/bruxo.png' },
    { nome: 'Monge', img: 'assets/classes/monge.png' },
    { nome: 'Patrulheiro', img: 'assets/classes/patrulheiro.png' }
  ];

  selecionarRaca(raca: string) {
    this.personagem.raca = raca;
    this.etapa = 2;
  }

  selecionarClasse(classe: string) {
    this.personagem.classe = classe;
    this.etapa = 3;
  }

  definirAtributosManual(atributo: string, valor: number) {
    this.personagem.atributos[atributo as keyof typeof this.personagem.atributos] = valor;
  }

  rolarAtributos() {
    for (const atributo in this.personagem.atributos) {
      if (this.personagem.atributos.hasOwnProperty(atributo)) {
        this.personagem.atributos[atributo] = this.rolarDado(6) + this.rolarDado(6) + this.rolarDado(6);
      }
    }
  }

  rolarDado(lados: number): number {
    return Math.floor(Math.random() * lados) + 1;
  }

  avancarEtapa() {
    this.etapa++;
  }

  voltarEtapa() {
    if (this.etapa > 1) {
      this.etapa--;
    }
  }
}
